define('services/features',['module', 'core/logger'], function (module, loggerFactory) {
  'use strict';

  var config = module.config();
  var featuresVisibilityList = config.visibility || {};
  var featuresKeys = Object.keys(featuresVisibilityList);
  var logger = loggerFactory('services/features');
  var buildRegexp = lookupPath => {
    lookupPath = lookupPath.replace('*', '\\S+');
    try {
      return new RegExp("^".concat(lookupPath, "$"));
    } catch (e) {
      logger.warn("Lookup feature path ".concat(lookupPath, " was not found"));
      return new RegExp('^\0$');
    }
  };
  return {
    isVisible() {
      var featurePath = arguments.length > 0 && arguments[0] !== undefined ? arguments[0] : '';
      var isVisibleByDefault = arguments.length > 1 && arguments[1] !== undefined ? arguments[1] : true;
      var matchingPath = null;
      featuresKeys.some(path => {
        var exactMatch = path === featurePath;
        if (exactMatch || buildRegexp(path).test(featurePath)) {
          matchingPath = path;
        }
        if (exactMatch) {
          return true;
        }
      });
      return matchingPath === null ? isVisibleByDefault : featuresVisibilityList[matchingPath] === 'show';
    }
  };
});
